import React, { useState } from "react";
import "./Menu.css";

const Menu = () => {
  const items = ["Головна", "Події", "Новини", "Про нас"];
  const [active, setActive] = useState("Головна");

  return (
    <nav className="menu">
      <ul>
        {items.map((item) => (
          <li
            key={item}
            className={active === item ? "active" : ""}
            onClick={() => setActive(item)}
          >
            {item}
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Menu;
